#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

int main() {
  vector<int> numbers = {5, 2, 8, 1, 9, 3};

  sort(numbers.begin(), numbers.end());

  cout << "Sorted: ";
  for (int n : numbers) {
    cout << n << " ";
  }
  cout << endl;

  auto it = find(numbers.begin(), numbers.end(), 8);
  if (it != numbers.end()) {
    cout << "Found 8 at position " << (it - numbers.begin()) << endl;
  }
  return 0;
}
